#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char s[200005];
    while(T--){
        scanf("%s", s);
        int n = strlen(s);
        int freq[26] = {0};
        for(int i=0;i<n;i++) freq[s[i]-'a']++;
        int answer = n; // upper bound
        for(int ch=0; ch<26; ++ch){
            int cnt = freq[ch];
            if(cnt<=1){ answer = 0; continue; }
            // prefix sums for this character
            static int pref[200006];
            pref[0]=0;
            for(int i=0;i<n;i++) pref[i+1]=pref[i]+(s[i]-'a'==ch);
            int best = 0;
            for(int i=0;i+cnt<=n;i++){
                int inside = pref[i+cnt]-pref[i];
                if(inside>best) best=inside;
            }
            int swaps = cnt - best;
            if(swaps<answer) answer=swaps;
        }
        printf("%d\n", answer);
    }
    return 0;
}

