#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        string s; cin>>s;
        int n=s.size();
        int freq[26] = {};
        for(char c: s) freq[c-'a']++;
        int ans=n;
        for(int ch=0; ch<26; ++ch){
            int cnt=freq[ch];
            if(cnt<=1){ ans=0; continue; }
            vector<int> pref(n+1,0);
            for(int i=0;i<n;i++) pref[i+1]=pref[i]+(s[i]-'a'==ch);
            int best=0;
            for(int i=0;i+cnt<=n;i++){
                int inside=pref[i+cnt]-pref[i];
                best=max(best,inside);
            }
            ans=min(ans,cnt-best);
        }
        cout<<ans<<"\n";
    }
    return 0;
}

